Use **`WebApplicationFactory<TEntryPoint>`** from `Microsoft.AspNetCore.Mvc.Testing`. It hosts your entire ASP.NET Core pipeline in-memory and gives you an `HttpClient` — no ports, no real server.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
dotnet add tests/MyMcp.Tests package xunit
```

### Example test class

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first (required by protocol)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/list"
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task InitializeSession()
    {
        var init = new
        {
            jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        await _client.PostAsJsonAsync("/mcp", init);
    }
}
```

### Key points

| Concept | Detail |
|---|---|
| **No real server** | `WebApplicationFactory` uses `TestServer` internally — all in-process |
| **Full pipeline** | Middleware, DI, routing all run exactly as in production |
| **Custom services** | Override `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in mocks (e.g., fake DB) |
| **SSE streams** | For Streamable HTTP, use `SendAsync` with `HttpCompletionOption.ResponseHeadersRead` and read the response stream line-by-line |
| **Session state** | If your server uses `Mcp-Session-Id`, capture it from the `initialize` response and set it as a header on subsequent requests |

> **Tip:** Make sure `Program` is accessible to your test project — add `<InternalsVisibleTo Include="MyMcp.Tests" />` to your server's `.csproj`, or use a `public partial class Program { }` marker at the bottom of `Program.cs`.
